import{c as s,Q as n,j as a,m as e}from"./chunks/framework.CBiVa4O3.js";const g=JSON.parse('{"title":"从 GPT 到 LLM:自回归生成","description":"","frontmatter":{},"headers":[],"relativePath":"../aiLearning/14-从GPT到LLM-自回归生成.md","filePath":"../aiLearning/14-从GPT到LLM-自回归生成.md","lastUpdated":1778496697000}'),o={name:"../aiLearning/14-从GPT到LLM-自回归生成.md"};function i(l,t,p,d,r,h){return n(),a("div",null,[...t[0]||(t[0]=[e(`<h1 id="从-gpt-到-llm-自回归生成" tabindex="-1">从 GPT 到 LLM:自回归生成 <a class="header-anchor" href="#从-gpt-到-llm-自回归生成" aria-label="Permalink to &quot;从 GPT 到 LLM:自回归生成&quot;">​</a></h1><p>13 篇把 Transformer Block 拆透了。这一篇回答两个问题:</p><ol><li><strong>为什么&quot;猜下一个词&quot;这件看起来很笨的事,能做出像样的智能?</strong></li><li><strong>2017 到 2026,Transformer 是怎么一路膨胀成 GPT-5、Claude 4.7 这种&quot;会推理的怪物&quot;的?</strong></li></ol><blockquote><p>一句话先记住:<strong>LLM = Decoder-Only Transformer + 自回归 next-token prediction + 大规模预训练 + 后训练对齐</strong>。这四个东西哪一样都不能少。</p></blockquote><hr><h2 id="一、encoder-only-decoder-only-encoder-decoder" tabindex="-1">一、Encoder-Only / Decoder-Only / Encoder-Decoder <a class="header-anchor" href="#一、encoder-only-decoder-only-encoder-decoder" aria-label="Permalink to &quot;一、Encoder-Only / Decoder-Only / Encoder-Decoder&quot;">​</a></h2><p>13 篇讲过,2026 年 Decoder-Only 一统江湖。但回到 2018 年,三派旗鼓相当。先把分歧讲清楚:</p><table tabindex="0"><thead><tr><th>流派</th><th>代表</th><th>训练任务</th><th>看序列方向</th><th>适合</th></tr></thead><tbody><tr><td>Encoder-Only</td><td>BERT、RoBERTa</td><td>MLM(完形填空)</td><td>双向</td><td>分类、抽取、语义匹配</td></tr><tr><td>Decoder-Only</td><td>GPT、Claude、Llama</td><td>Next Token Prediction</td><td>单向(只看左边)</td><td>生成、对话、推理</td></tr><tr><td>Encoder-Decoder</td><td>T5、BART、原 Transformer</td><td>seq2seq 各种任务</td><td>Encoder 双向 + Decoder 单向</td><td>翻译、摘要</td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BERT(Encoder-Only):</span></span>
<span class="line"><span>  输入:[CLS] I [MASK] you [SEP]</span></span>
<span class="line"><span>  目标:猜出 [MASK] 是 &quot;love&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>GPT(Decoder-Only):</span></span>
<span class="line"><span>  输入:[BOS] I love</span></span>
<span class="line"><span>  目标:预测下一个词 &quot;you&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>T5(Encoder-Decoder):</span></span>
<span class="line"><span>  输入(Encoder):translate English to Chinese: I love you</span></span>
<span class="line"><span>  输出(Decoder):我  爱  你</span></span></code></pre></div><blockquote><p><strong>关键差异</strong>:BERT 看双向但不能直接生成,GPT 只看单向但天然能生成。这个<strong>单向 vs 双向</strong>之争,是 2018-2022 之间整个 NLP 的主旋律。</p></blockquote><hr><h2 id="二、decoder-only-的自回归-next-token-prediction" tabindex="-1">二、Decoder-Only 的自回归:next token prediction <a class="header-anchor" href="#二、decoder-only-的自回归-next-token-prediction" aria-label="Permalink to &quot;二、Decoder-Only 的自回归:next token prediction&quot;">​</a></h2><p>GPT 的训练目标极简:<strong>给定前面的 token,预测下一个 token</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>训练数据(一句话当 N 个训练样本):</span></span>
<span class="line"><span>  &quot;我 爱 你&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>训练时(并行,所有位置一起):</span></span>
<span class="line"><span>  位置 0: 看 [&lt;bos&gt;]                  → 预测 &quot;我&quot;</span></span>
<span class="line"><span>  位置 1: 看 [&lt;bos&gt;, 我]              → 预测 &quot;爱&quot;</span></span>
<span class="line"><span>  位置 2: 看 [&lt;bos&gt;, 我, 爱]          → 预测 &quot;你&quot;</span></span>
<span class="line"><span>  位置 3: 看 [&lt;bos&gt;, 我, 爱, 你]      → 预测 &quot;&lt;eos&gt;&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>loss = CrossEntropy(每个位置的预测 vs 真实下一个 token) 的平均</span></span></code></pre></div><p>数学上:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L = -Σ log P(x_t | x_&lt;t; θ)         # 负对数似然(就是 CE loss)</span></span></code></pre></div><p>推理时也是同一套机制,只是<strong>串行生成</strong>,把上一步的输出接到输入末尾再跑一次:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 极简的自回归生成循环</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> generate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(model, tokens, max_new</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">):</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> range</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(max_new):</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        logits </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> model(tokens)              </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># (1, N, vocab)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        next_token </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> logits[:, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">].argmax(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">dim</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 取最后位置 + greedy</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        tokens </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torch.cat([tokens, next_token[:, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">None</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]], </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">dim</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> next_token.item() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> EOS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">            break</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tokens</span></span></code></pre></div><blockquote><p><strong>核心问题</strong>:为什么这么简单的目标能 scale 出智能?</p><p>因为&quot;预测下一个词&quot;这件事,<strong>逼着模型隐式学会了世界上几乎所有结构化知识</strong>:</p><ul><li>要预测下一个词是 &quot;Paris&quot; 还是 &quot;London&quot;,得知道地理</li><li>要预测下一个词是数学表达式的对的下一个,得&quot;会算&quot;</li><li>要预测下一个词补全一个论证,得有逻辑</li></ul><p>一个足够强的下一个词预测器 = 一个压缩了人类知识的世界模型。这是 Sutskever 反复强调的观点。</p></blockquote><hr><h2 id="三、kv-cache-直觉" tabindex="-1">三、KV Cache 直觉 <a class="header-anchor" href="#三、kv-cache-直觉" aria-label="Permalink to &quot;三、KV Cache 直觉&quot;">​</a></h2><p>推理时一个不起眼但极重要的优化。33 篇会详讲实现,这里建立直觉。</p><p>朴素自回归生成的问题:<strong>每生成一个新 token,都要把整段输入再跑一遍 Transformer</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>step 1: 输入 [a]            算 N=1 个位置的 attention</span></span>
<span class="line"><span>step 2: 输入 [a, b]         算 N=2 个位置(其中 [a] 又重算了一次)</span></span>
<span class="line"><span>step 3: 输入 [a, b, c]      算 N=3 个位置(其中 [a, b] 又重算了一次)</span></span></code></pre></div><p>仔细看 <strong>causal mask 下,过去 token 的 K、V 永远不变</strong>——它们看不到后面的 token。所以可以缓存:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>step 1: 算 K_1, V_1,缓存</span></span>
<span class="line"><span>step 2: 只算 K_2, V_2,接到缓存后面;新 Q_2 和 [K_1, K_2] 算 attention</span></span>
<span class="line"><span>step 3: 只算 K_3, V_3,接到缓存后面;新 Q_3 和 [K_1, K_2, K_3] 算 attention</span></span></code></pre></div><table tabindex="0"><thead><tr><th>不用 KV Cache</th><th>用 KV Cache</th></tr></thead><tbody><tr><td>每步 O(N²) 计算</td><td>每步 O(N) 计算</td></tr><tr><td>生成 100 token 慢</td><td>快 10 倍以上</td></tr><tr><td>显存:不需</td><td>显存:N · num_layers · 2 · d_model</td></tr></tbody></table><p>代价是显存。一个长 prompt(几万 token)的 KV Cache 可能占几 GB。这就是为什么:</p><ul><li>API 计价里 input token 比 output token 便宜(input 一次 prefill,output 每个都要 decode)</li><li>vLLM、SGLang 这些推理框架都在围绕 KV Cache 做优化(PagedAttention、Prefix Caching)</li><li>Anthropic、OpenAI 都推 prompt caching 功能,本质是把常用 prompt 的 KV Cache 持久化</li></ul><blockquote><p>33 篇会从工程角度讲 KV Cache 的存储布局、连续 batch、Prefix Sharing 等。这里你只要记住<strong>KV Cache 让自回归生成从 O(N²) 降到 O(N)</strong>,是现代 LLM 推理性能的命脉。</p></blockquote><hr><h2 id="四、bert-vs-gpt-的范式分野" tabindex="-1">四、BERT vs GPT 的范式分野 <a class="header-anchor" href="#四、bert-vs-gpt-的范式分野" aria-label="Permalink to &quot;四、BERT vs GPT 的范式分野&quot;">​</a></h2><p>2018-2020 这段时间,业界普遍认为 BERT 派会赢。原因合理:</p><table tabindex="0"><thead><tr><th>维度</th><th>BERT(Encoder-Only)</th><th>GPT(Decoder-Only)</th></tr></thead><tbody><tr><td>看上下文</td><td>双向</td><td>单向</td></tr><tr><td>在 GLUE/SQuAD 上</td><td>直接 SOTA</td><td>需要更多 trick</td></tr><tr><td>生成</td><td>不能直接生成</td><td>天生会生成</td></tr><tr><td>训练任务</td><td>MLM(填空)</td><td>Next Token Prediction</td></tr></tbody></table><p>BERT 的 MLM 看起来更&quot;扎实&quot;——能利用全文信息,还能针对不同下游任务微调出各种小模型。当时的范式是:<strong>预训练一个 BERT,针对每个任务 fine-tune 出一个分类头</strong>。</p><p>GPT 走的是另一条路:<strong>所有任务都重新表达成&quot;续写&quot;</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>分类:&quot;评价: 这电影真好看  情感:&quot; → 续写 &quot;正面&quot;</span></span>
<span class="line"><span>QA:  &quot;问: 中国首都  答:&quot; → 续写 &quot;北京&quot;</span></span>
<span class="line"><span>翻译:&quot;翻译: I love you -&gt;&quot; → 续写 &quot;我爱你&quot;</span></span></code></pre></div><p>这就是 <strong>Prompt 范式</strong>的雏形。到 GPT-3 时,这个范式优势开始压倒 BERT:</p><table tabindex="0"><thead><tr><th>维度</th><th>BERT 派</th><th>GPT 派</th></tr></thead><tbody><tr><td>适配新任务</td><td>必须 fine-tune</td><td><strong>改 Prompt 就行</strong>(in-context learning)</td></tr><tr><td>模型数量</td><td>每个任务一个</td><td>一个模型万能</td></tr><tr><td>Scale 效果</td><td>边际收益递减</td><td>越大越通用</td></tr><tr><td>用户接口</td><td>API 接 + 后处理</td><td>一个对话框搞定</td></tr></tbody></table><blockquote><p><strong>决定性时刻</strong>:2020 GPT-3(175B),展示了&quot;用大参数 + 大数据 + 单纯 next token prediction&quot;也能在 zero-shot/few-shot 下打 BERT-style fine-tune,而且<strong>接口通用</strong>。从这刻起,大家发现 BERT 这条路 scale 不上去。</p></blockquote><hr><h2 id="五、为什么-decoder-only-赢了" tabindex="-1">五、为什么 Decoder-Only 赢了 <a class="header-anchor" href="#五、为什么-decoder-only-赢了" aria-label="Permalink to &quot;五、为什么 Decoder-Only 赢了&quot;">​</a></h2><p>复盘下来,Decoder-Only 的胜利不是偶然:</p><h3 id="_1-接口统一-一切皆生成" tabindex="-1">1. 接口统一:一切皆生成 <a class="header-anchor" href="#_1-接口统一-一切皆生成" aria-label="Permalink to &quot;1. 接口统一:一切皆生成&quot;">​</a></h3><p>写代码、聊天、做数学题、调 API、规划任务——<strong>全都能表达成&quot;输入 prompt → 输出文本&quot;</strong>。这种接口的统一性,让一个模型能干所有事,也让用户不用学 N 套 API。</p><h3 id="_2-scale-友好" tabindex="-1">2. Scale 友好 <a class="header-anchor" href="#_2-scale-友好" aria-label="Permalink to &quot;2. Scale 友好&quot;">​</a></h3><p>经验上,Decoder-Only 的 loss 和参数量、数据量、算力的关系非常干净(这就是 Scaling Law,19 篇详讲)。<strong>给资源就涨能力,这是工业化的前提</strong>。</p><h3 id="_3-训练目标无歧义" tabindex="-1">3. 训练目标无歧义 <a class="header-anchor" href="#_3-训练目标无歧义" aria-label="Permalink to &quot;3. 训练目标无歧义&quot;">​</a></h3><p>Next Token Prediction 没有任何 trick:就是 CE loss,就是预测下一个 token。BERT 的 MLM 还有 mask 比例怎么选、是否要 NSP(下一句预测)等讨论,GPT 这边干净得多。</p><h3 id="_4-自然支持-in-context-learning" tabindex="-1">4. 自然支持 in-context learning <a class="header-anchor" href="#_4-自然支持-in-context-learning" aria-label="Permalink to &quot;4. 自然支持 in-context learning&quot;">​</a></h3><p>放几个 example 在 prompt 里,模型就能照着例子做新任务。这个能力来自&quot;模型在预训练时见过类似分布的多任务混合数据&quot;,是 Decoder-Only + Scale 涌现出来的。</p><h3 id="_5-工程链路成熟" tabindex="-1">5. 工程链路成熟 <a class="header-anchor" href="#_5-工程链路成熟" aria-label="Permalink to &quot;5. 工程链路成熟&quot;">​</a></h3><p>KV Cache、流式输出、推理优化、RLHF、function calling……整个生态都围绕 Decoder-Only 建。BERT 派想跟上得重新搞,但 BERT 的市场已经被吃掉了。</p><blockquote><p><strong>2026 年共识</strong>:除非你有非常具体的需求(比如端侧分类、embedding 检索),否则就用 Decoder-Only LLM。23 篇会专门讲 embedding 模型,那是 BERT 派至今还活着的领域。</p></blockquote><hr><h2 id="六、scale-的故事" tabindex="-1">六、Scale 的故事 <a class="header-anchor" href="#六、scale-的故事" aria-label="Permalink to &quot;六、Scale 的故事&quot;">​</a></h2><p>把过去几年的旗舰模型摆一起,数字一目了然:</p><table tabindex="0"><thead><tr><th>模型</th><th>年份</th><th>参数量</th><th>上下文</th><th>关键事件</th></tr></thead><tbody><tr><td>GPT-1</td><td>2018</td><td>117M</td><td>512</td><td>证明 pretrain + finetune 可行</td></tr><tr><td>GPT-2</td><td>2019</td><td>1.5B</td><td>1024</td><td>&quot;太危险不能放出来&quot;梗</td></tr><tr><td>GPT-3</td><td>2020</td><td><strong>175B</strong></td><td>2048</td><td>few-shot 在线,Decoder-Only 初次封神</td></tr><tr><td>InstructGPT / ChatGPT</td><td>2022</td><td>175B</td><td>4k</td><td>RLHF + 对话,产品爆炸</td></tr><tr><td>GPT-4</td><td>2023</td><td>~1.8T(MoE,推测)</td><td>8k → 128k</td><td>多模态、推理跃升</td></tr><tr><td>GPT-4o</td><td>2024</td><td>未公开</td><td>128k</td><td>原生多模态、低延迟</td></tr><tr><td>o1 / o3</td><td>2024-2025</td><td>未公开</td><td>128k+</td><td>&quot;思考链推理&quot;,强化学习对齐</td></tr><tr><td><strong>GPT-5</strong></td><td>2025-2026</td><td>未公开(估 数 T 级)</td><td>1M+</td><td>更强推理、更长 context、更稳工具使用</td></tr></tbody></table><p>Anthropic 这条线:</p><table tabindex="0"><thead><tr><th>模型</th><th>关键事件</th></tr></thead><tbody><tr><td>Claude 1 / 2</td><td>2023,主打长 context(100k)、Constitutional AI</td></tr><tr><td>Claude 3(Opus/Sonnet/Haiku)</td><td>2024,三档分级,Opus 对标 GPT-4</td></tr><tr><td>Claude 3.5 / 3.7 Sonnet</td><td>2024-2025,Sonnet 性价比之王,Computer Use 出现</td></tr><tr><td>Claude 4 / 4.5 / <strong>4.7</strong></td><td>2025-2026,<strong>1M context、可控 thinking、agent 一线</strong></td></tr></tbody></table><p>其他重要选手:Google Gemini(2 / 2.5 / 3,2M context、原生多模态),Meta Llama 3 / 4(开源旗舰,商用主流),Mistral / Qwen / DeepSeek(国产/欧洲开源强力)。</p><blockquote><p><strong>Scale 的另一个侧面</strong>:<strong>模型不是简单&quot;变大&quot;,而是同时</strong>:</p><ul><li>训练数据从几百 GB 扩到 PB 级</li><li>训练算力从单机 GPU 扩到几万张 H100/B200</li><li>上下文从 2k 扩到 1M+</li><li>训练范式从 next-token 加入 SFT、RLHF、RLAIF、过程奖励、思考链 RL 等 19 篇专讲 Scaling Law,17 篇讲训练范式演进。</li></ul></blockquote><hr><h2 id="七、scaling-law-与涌现的伏笔" tabindex="-1">七、Scaling Law 与涌现的伏笔 <a class="header-anchor" href="#七、scaling-law-与涌现的伏笔" aria-label="Permalink to &quot;七、Scaling Law 与涌现的伏笔&quot;">​</a></h2><p>为什么大家敢往里砸百亿美金?<strong>因为 Scaling Law 是经验上可预测的</strong>。</p><p>OpenAI 2020 年的论文给出:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Loss(N, D, C) ≈ A · N^(-α) + B · D^(-β) + C^(-γ)</span></span></code></pre></div><p>N = 参数量,D = 数据量,C = 算力。<strong>给定预算,你能算出最优 N 和 D</strong>。</p><p>DeepMind 2022 年的 Chinchilla 论文修正了配比:<strong>参数和 token 数应该 1:20 大致同步增长</strong>。这直接指导了 Llama 系列(7B → 1.4T tokens,接近这个配比)。</p><p><strong>涌现(Emergent Abilities)</strong>:有些能力(比如多步算术、链式推理、follow 多步指令)在小模型上<strong>完全不会</strong>,模型大到某个临界点突然就有了。这是 GPT-3 之后大家不再小打小闹的根本原因——你不知道下一个 10x scale 会冒出什么新能力。</p><blockquote><p>19 篇会展开 Scaling Law 的细节、Chinchilla 的修正、最近&quot;推理时算力 scale&quot;(o1/o3 类)的范式。先建立直觉:<strong>今天主流 LLM 训练的费用动辄数千万到数亿美金,押的就是 Scaling Law 不会失效</strong>。</p></blockquote><p>2024-2026 这两年的新故事是 <strong>inference-time scale</strong>:让模型在推理时多想一会儿(o1、o3、Claude 的 extended thinking),效果远好过单纯把参数堆更大。这是 LLM 进入&quot;会推理&quot;阶段的标志。</p><hr><h2 id="八、自回归的根本缺陷" tabindex="-1">八、自回归的根本缺陷 <a class="header-anchor" href="#八、自回归的根本缺陷" aria-label="Permalink to &quot;八、自回归的根本缺陷&quot;">​</a></h2><p>把 LLM 吹完,得给一盆冷水。<strong>自回归生成有几个绕不过去的硬伤</strong>:</p><h3 id="_1-幻觉-hallucination" tabindex="-1">1. 幻觉(Hallucination) <a class="header-anchor" href="#_1-幻觉-hallucination" aria-label="Permalink to &quot;1. 幻觉(Hallucination)&quot;">​</a></h3><p>模型的目标只是&quot;下一个 token 概率最大&quot;,不是&quot;说真话&quot;。当训练数据没覆盖到、或者模型推理失败时,它会<strong>自信地编造</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你: 介绍一下《2025 年深度学习圣经》这本书。</span></span>
<span class="line"><span>LLM: 这本书由 Yann LeCun 和 Geoffrey Hinton 合著,2025 年出版,共 800 页……(完全编的)</span></span></code></pre></div><p>为什么会这样:loss 函数从来没说&quot;不会就别说&quot;,它的目标就是&quot;接出概率最高的下一个 token&quot;。</p><h3 id="_2-不能-想清楚再写" tabindex="-1">2. 不能&quot;想清楚再写&quot; <a class="header-anchor" href="#_2-不能-想清楚再写" aria-label="Permalink to &quot;2. 不能&quot;想清楚再写&quot;&quot;">​</a></h3><p>一旦输出第一个 token,就不能反悔了。<strong>前几个 token 错了,后面就一路跟着错</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>问: 27 × 38 = ?</span></span>
<span class="line"><span>传统 LLM: 直接答 → &quot;1100&quot;(错的,正确是 1026)</span></span></code></pre></div><p>为什么?因为传统自回归没有&quot;先在心里草稿,再下笔&quot;这个机制。<strong>所有思考都必须以 token 形式表达出来才存在</strong>。</p><p>这就是 <strong>Chain-of-Thought(CoT)</strong> prompt 兴起的原因——让模型先输出推理过程,再得结论:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>问: 27 × 38 = ?</span></span>
<span class="line"><span>LLM(加 &quot;step by step&quot;): </span></span>
<span class="line"><span>  27 × 38 = 27 × (40 - 2) </span></span>
<span class="line"><span>         = 27 × 40 - 27 × 2 </span></span>
<span class="line"><span>         = 1080 - 54 </span></span>
<span class="line"><span>         = 1026</span></span></code></pre></div><p>更进一步,o1、o3、Claude extended thinking 把 CoT 做成<strong>默认机制</strong>:</p><table tabindex="0"><thead><tr><th>传统 LLM</th><th>&quot;会想&quot;的 LLM</th></tr></thead><tbody><tr><td>输入 prompt → 直接答</td><td>输入 prompt → 内部&quot;思考&quot;几千 token → 答</td></tr><tr><td>输出 = 思考</td><td>思考 ≠ 输出(可隐藏)</td></tr><tr><td>算力主要花在训练</td><td>大量算力花在推理时思考</td></tr></tbody></table><p>这套范式来自 <strong>inference-time scaling + 强化学习</strong>(让模型自己学怎么&quot;想得更对&quot;,而不是只学&quot;接得更顺&quot;)。</p><h3 id="_3-长度归一性" tabindex="-1">3. 长度归一性 <a class="header-anchor" href="#_3-长度归一性" aria-label="Permalink to &quot;3. 长度归一性&quot;">​</a></h3><p>自回归是&quot;一路向前&quot;,<strong>没法回头改</strong>。Diffusion 类的非自回归模型在图像和小规模文本上有不同特性,但在通用 LLM 上,自回归依然是 2026 年的最优解。</p><blockquote><p>17 篇讲训练范式时会展开 RLHF / RLAIF / 过程奖励等。要点先记住:<strong>单纯 next-token prediction 解决不了&quot;想清楚再说&quot;的问题,需要在训练阶段引入额外的目标信号</strong>。</p></blockquote><h3 id="_4-对齐成本" tabindex="-1">4. 对齐成本 <a class="header-anchor" href="#_4-对齐成本" aria-label="Permalink to &quot;4. 对齐成本&quot;">​</a></h3><p>裸预训练出来的模型不会&quot;听话&quot;,会瞎说、会跑题、会被诱导说危险内容。要做成 ChatGPT、Claude 这种产品,需要 SFT + RLHF + Constitutional AI / RLAIF 等大量后训练工程。<strong>对齐有时候比预训练还贵</strong>。</p><hr><h2 id="九、给应用工程师的影响" tabindex="-1">九、给应用工程师的影响 <a class="header-anchor" href="#九、给应用工程师的影响" aria-label="Permalink to &quot;九、给应用工程师的影响&quot;">​</a></h2><p>如果你是做应用层的(写 Agent、做 RAG、搭 AI 产品),上面这些原理直接决定你怎么用 LLM:</p><ol><li><strong>理解&quot;上下文 = KV Cache&quot;</strong>:你给 LLM 的每个字都要花钱花延迟。<strong>精简 prompt、用 prompt caching、合理切 chunk</strong> 是基本功(24 篇详讲 Context Engineering)</li><li><strong>接受幻觉是常态</strong>:别指望 LLM 自己&quot;知道自己不知道&quot;。重要事实<strong>必须 RAG 进去 + 要求引用</strong>(22 篇)</li><li><strong>复杂任务先让它想</strong>:能加 CoT 就加,能用 thinking 模式就用。<strong>别让它&quot;一口气说出来&quot;</strong></li><li><strong>流式输出是 UX 必需品</strong>:自回归本质是 token 流,前端<strong>别等全部返回再渲染</strong>,否则用户体感差到爆</li><li><strong>不同模型选型有差异</strong>: <ul><li>高质量推理 → Claude 4.7 / GPT-5 / Gemini 3</li><li>低延迟 / 大批量 → Haiku / GPT-5-mini / Gemini Flash</li><li>私有部署 → Llama 4 / Qwen / DeepSeek</li></ul></li><li><strong>API 计费看 input/output</strong>:写长 prompt 比写长输出便宜,但都要花钱;<strong>长 context 不等于免费</strong></li><li><strong>不要纠结 &quot;GPT 还是 Claude&quot;</strong>:能力相近,挑顺手的。<strong>关键是设计好 prompt、上下文、工具,这些迁移成本很低</strong>(2026 各家 API 早就互通)</li><li><strong>理解涌现 = 理解模型的&quot;性格&quot;</strong>:不同 size 的模型适合不同任务,<strong>给小模型分类、给大模型推理</strong>,合理分工省钱省延迟</li></ol><blockquote><p><strong>一个底层心智模型</strong>:LLM 是一个被压缩了人类大量知识的&quot;概率续写器&quot;。<strong>理解这件事,你就不会指望它代替数据库,也不会用它做精确计算</strong>(那些用工具调用解决,21 篇)。</p></blockquote><hr><p>下一篇:<code>15-Tokenizer与BPE.md</code>,补完 LLM 的最后一块拼图——<strong>文字到 token 是怎么变的</strong>。看完你才能彻底理解为什么 emoji 算 5 个 token、为什么中文按 API 计费比英文贵、为什么模型对某些&quot;切错位置&quot;的输入会犯傻。</p>`,100)])])}const u=s(o,[["render",i]]);export{g as __pageData,u as default};
